\begin{lemma}\label{lemma:shift-gcd}
Let $A,B$ be shift operators in $\Sh$. 
If $\gcld_\Sh(A,B)$ is a power of~$S_n$, then so is $\gcld_\Sh
(A,BS_n^m)$ for any $m\in\mathbb N$.
\end{lemma}

