\begin{lemma}
Let $P\in\FrecZ$ be the fraction $(\Pnum,\Pden) = (S_n^\ell\Hnum,S_n^\ell\Hden)$ with $\gcld_\Sh(\Hnum,\Hden)=1$. Then the product $P \otimes (\Dnum,\Dden)$ has the
same form.    
\end{lemma}

